const fs = require('fs');
const path = require('path');

// Usage: node updateBadges.cjs /absolute/path/to/Clubs.json
const clubsPathArg = process.argv[2];
const clubsPath = clubsPathArg || path.resolve(__dirname, '..', 'public', 'assets', 'Clubs.json');

if (!fs.existsSync(clubsPath)) {
  console.error('Clubs.json not found at:', clubsPath);
  process.exit(2);
}

const backupPath = clubsPath + '.bak';
try {
  fs.copyFileSync(clubsPath, backupPath, fs.constants.COPYFILE_EXCL);
  console.log('Backup created at', backupPath);
} catch (err) {
  if (err.code === 'EEXIST') {
    console.log('Backup already exists at', backupPath);
  } else {
    console.error('Failed to create backup:', err);
    process.exit(3);
  }
}

let raw = fs.readFileSync(clubsPath, 'utf8');
let data;
try {
  data = JSON.parse(raw);
} catch (err) {
  console.error('Failed to parse JSON:', err);
  process.exit(4);
}

let updated = 0;
let skippedEmpty = 0;
for (let obj of data) {
  const verein = (obj.Verein || '').toString().trim();
  if (!verein) {
    obj.badge = '';
    skippedEmpty++;
    continue;
  }
  // Remove spaces only (all whitespace sequences) and also remove non-filename chars
  const safe = verein.replace(/\s+/g, '').replace(/[^a-zA-Z0-9\-_.]/g, '');
  const filename = safe + '.png';
  obj.badge = './assets/Logos/' + filename;
  updated++;
}

fs.writeFileSync(clubsPath, JSON.stringify(data, null, 2) + '\n', 'utf8');
console.log(`Done. Updated ${updated} entries. Set empty badge for ${skippedEmpty} entries with empty "Verein".`);
console.log('Original backup at', backupPath);
